customCSS:
/* Wood Paneling - Warm Rustic */
@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;600;700&family=Lato:wght@300;400;700&family=Source+Code+Pro&display=swap');

.cyber-grid {
  background: none;
  animation: none;
}

.cyber-glow {
  background: 
    radial-gradient(ellipse 600px 400px at 30% 10%, rgba(176, 136, 96, 0.08), transparent),
    radial-gradient(ellipse 500px 350px at 70% 90%, rgba(232, 160, 64, 0.05), transparent);
}

.cyber-particles { display: none; }

.stat-card {
  border: 1px solid rgba(176, 136, 96, 0.2);
  background: rgba(48, 36, 24, 0.9);
}

.stat-card::before {
  background: linear-gradient(90deg, #b08860, #c49a6c, #e8a040);
  height: 2px;
}

.stat-card:hover {
  border-color: rgba(196, 154, 108, 0.35);
  box-shadow: 0 4px 20px rgba(176, 136, 96, 0.12);
}

.stat-value {
  text-shadow: none;
}

.celebration-title {
  color: #e8a040 !important;
  text-shadow: 0 0 20px rgba(232, 160, 64, 0.4);
}

.miner-card, .health-card, .lifetime-card {
  background: rgba(48, 36, 24, 0.7);
  border: 1px solid rgba(176, 136, 96, 0.12);
}

.miner-card:hover {
  border-color: rgba(196, 154, 108, 0.25);
}
